// Package gogenfilter detects and filters auto-generated Go code files.
//
// It identifies files generated by common tools including
// gendocs:generator-list:start
// sqlc, templ, go-enum, protobuf, oapi-codegen, deepcopy-gen, wire, moq, mockgen, stringer, mockery, ent, gqlgen, easyjson, msgp, counterfeiter, go-swagger, and any tool using the standard "Code generated by" comment convention
// gendocs:generator-list:end
// per https://go.dev/s/generatedcode.
//
// Detection is two-phase: filename-based first (zero I/O), then content-based
// (reads file). This optimization avoids unnecessary file reads.
//
// # Quick Start
//
// Create a filter with functional options:
//
//	opts, err := gogenfilter.WithFilterOptions(gogenfilter.FilterAll)
//	if err != nil {
//	    log.Fatal(err)
//	}
//	f, err := gogenfilter.NewFilter(opts)
//	if err != nil {
//	    log.Fatal(err)
//	}
//
// Check files — Filter returns (bool, error) to propagate I/O errors:
//
//	filtered, err := f.Filter("db/models.go")
//	if err != nil {
//	    log.Fatal(err)
//	}
//	if filtered {
//	    fmt.Println("skipping generated file")
//	}
//
// For low-level detection without a Filter:
//
//	reason := gogenfilter.DetectReason("file.go", content,
//	    gogenfilter.FilterSQLC,
//	    gogenfilter.FilterGeneric,
//	)
package gogenfilter
